@page "/write-review"
@rendermode InteractiveServer
@using sv_01a9e42ff556400f89d6b1f2b870af43.Models
@using sv_01a9e42ff556400f89d6b1f2b870af43.Services
@inject ReviewService ReviewService

<PageTitle>Write a Review</PageTitle>

<h3>Write a Review</h3>

@if (_submitted)
{
    <div class="alert alert-success mt-3">
        <strong>Thank you!</strong> Your review has been submitted successfully.
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmitAsync" FormName="write-review">
        <DataAnnotationsValidator />

        <div class="mb-3">
            <label for="productName" class="form-label">Product Name</label>
            <InputText id="productName" class="form-control" @bind-Value="_model.ProductName" />
            <ValidationMessage For="() => _model.ProductName" />
        </div>

        <div class="mb-3">
            <label for="rating" class="form-label">Rating</label>
            <InputNumber id="rating" class="form-control" @bind-Value="_model.Rating" min="1" max="5" />
            <ValidationMessage For="() => _model.Rating" />
        </div>

        <div class="mb-3">
            <label for="reviewTitle" class="form-label">Review Title</label>
