+@page "/write-review"
+@rendermode InteractiveServer
+@using sv_01a9e42ff556400f89d6b1f2b870af43.Models
+@using sv_01a9e42ff556400f89d6b1f2b870af43.Services
+@inject ReviewService ReviewService
+
+<PageTitle>Write a Review</PageTitle>
+
+<h3>Write a Review</h3>
+
+@if (_submitted)
+{
+    <div class="alert alert-success mt-3">
+        <strong>Thank you!</strong> Your review has been submitted successfully.
+    </div>
+}
+else
+{
+    <EditForm Model="_model" OnValidSubmit="HandleSubmitAsync" FormName="write-review">
+        <DataAnnotationsValidator />
+
+        <div class="mb-3">
+            <label for="productName" class="form-label">Product Name</label>
+            <InputText id="productName" class="form-control" @bind-Value="_model.ProductName" />
+            <ValidationMessage For="() => _model.ProductName" />
+        </div>
+
+        <div class="mb-3">
+            <label for="rating" class="form-label">Rating</label>
+            <InputNumber id="rating" class="form-control" @bind-Value="_model.Rating" min="1" max="5" />
+            <ValidationMessage For="() => _model.Rating" />
+        </div>
+
+        <div class="mb-3">
+            <label for="reviewTitle" class="form-label">Review Title</label>
+            <InputText id="reviewTitle" class="form-control" maxlength="100" @bind-Value="_model.ReviewTitle" />
+            <ValidationMessage For="() => _model.ReviewTitle" />
+            @if (_serverErrors.ContainsKey("ReviewTitle"))
+            {
+                <div class="text-danger">@_serverErrors["ReviewTitle"]</div>
+            }
+        </div>
+
+        <div class="mb-3">
+            <label for="reviewBody" class="form-label">Review Body</label>
+            <InputTextArea id="reviewBody" class="form-control" rows="5" maxlength="2000" @bind-Value="_model.ReviewBody" />
+            <ValidationMessage For="() => _model.ReviewBody" />
+            @if (_serverErrors.ContainsKey("ReviewBody"))
+            {
+                <div class="text-danger">@_serverErrors["ReviewBody"]</div>
+            }
+        </div>
+
+        <div class="mb-3">
+            <label for="photos" class="form-label">Upload Photos (up to 3, JPG/PNG, max 5 MB each)</label>
+            <InputFile id="photos" class="form-control" multiple OnChange="OnPhotoSelected"
+                       accept=".jpg,.jpeg,.png,image/jpeg,image/png" />
+            @if (!string.IsNullOrEmpty(_photoError))
+            {
+                <div class="text-danger">@_photoError</div>
+            }
+            @if (_selectedPhotos.Count > 0)
+            {
+                <ul class="list-group mt-2">
+                    @foreach (var photo in _selectedPhotos)
+                    {
+                        <li class="list-group-item d-flex justify-content-between align-items-center">
+                            @photo.FileName
+                            <span class="badge bg-secondary">@FormatSize(photo.Size)</span>
+                        </li>
+                    }
+                </ul>
+            }
+        </div>
+
+        <button type="submit" class="btn btn-primary" disabled="@_isSubmitting">
+            @if (_isSubmitting)
+            {
+                <span class="spinner-border spinner-border-sm me-1" role="status" aria-hidden="true"></span>
+            }
+            Submit Review
+        </button>
+    </EditForm>
+}
+
+@code {
+    private const long MaxFileSize = 5 * 1024 * 1024; // 5 MB
+    private const int MaxPhotos = 3;
+    private static readonly string[] AllowedContentTypes = ["image/jpeg", "image/png"];
+
+    private ReviewModel _model = new();
+    private List<PhotoFile> _selectedPhotos = new();
+    private Dictionary<string, string> _serverErrors = new();
+    private string? _photoError;
+    private bool _submitted;
+    private bool _isSubmitting;
+
+    private async Task OnPhotoSelected(InputFileChangeEventArgs e)
+    {
+        _photoError = null;
+
+        if (e.FileCount > MaxPhotos)
+        {
+            _photoError = $"You can upload at most {MaxPhotos} photos.";
+            return;
+        }
+
+        var photos = new List<PhotoFile>();
+        foreach (var file in e.GetMultipleFiles(MaxPhotos))
+        {
+            if (!AllowedContentTypes.Contains(file.ContentType))
+            {
+                _photoError = $"'{file.Name}' is not a supported format. Only JPG and PNG are allowed.";
+                return;
+            }
+
+            if (file.Size > MaxFileSize)
+            {
+                _photoError = $"'{file.Name}' exceeds the 5 MB size limit.";
+                return;
+            }
+
+            using var stream = file.OpenReadStream(maxAllowedSize: MaxFileSize);
+            using var ms = new MemoryStream();
+            await stream.CopyToAsync(ms);
+
+            photos.Add(new PhotoFile
+            {
+                FileName = file.Name,
+                Size = file.Size,
+                Content = ms.ToArray()
+            });
+        }
+
+        _selectedPhotos = photos;
+    }
+
+    private async Task HandleSubmitAsync()
+    {
+        _serverErrors.Clear();
+        _isSubmitting = true;
+
+        try
+        {
+            var errors = await ReviewService.ValidateAndSubmitAsync(_model, _selectedPhotos);
+
+            if (errors.Count > 0)
+            {
+                _serverErrors = errors;
+                return;
+            }
+
+            _submitted = true;
+        }
+        finally
+        {
+            _isSubmitting = false;
+        }
+    }
+
+    private static string FormatSize(long bytes)
+    {
+        return bytes switch
+        {
+            < 1024 => $"{bytes} B",
+            < 1024 * 1024 => $"{bytes / 1024.0:F1} KB",
+            _ => $"{bytes / (1024.0 * 1024.0):F1} MB"
+        };
+    }
+}
